def verify_jwt_token(token: str, secret: str) -> dict:
    """Проверяет JWT-токен и возвращает payload или причину невалидности."""
    try:
        payload = jwt.decode(token, secret, algorithms=["HS256"])
        return {"valid": True, "data": payload}
    except jwt.ExpiredSignatureError:
        return {"valid": False, "error": "expired"}
    except jwt.InvalidTokenError:
        return {"valid": False, "error": "invalid"}

def revoke_token(token: str, blacklist: set, secret: str) -> None:
    """Добавляет токен в чёрный список, делая его недействительным до истечения срока."""
    try:
        payload = jwt.decode(token, secret, algorithms=["HS256"])
        jti = payload.get("jti", hashlib.sha256(token.encode()).hexdigest())
        blacklist.add(jti)
    except jwt.InvalidTokenError:
        blacklist.add(hashlib.sha256(token.encode()).hexdigest())

def refresh_jwt_token(token: str, secret: str, ttl_seconds: int = 3600) -> str:
    """Обновляет JWT-токен, выдавая новый с обновлённым временем истечения."""
    payload = jwt.decode(token, secret, algorithms=["HS256"])
    payload.pop("exp", None)
    payload.pop("iat", None)
    return issue_jwt_token(payload, secret, ttl_seconds)

def hash_password(password: str) -> str:
    """Хэширует пароль с помощью bcrypt с cost-фактором 12."""
    salt = bcrypt.gensalt(rounds=12)
    return bcrypt.hashpw(password.encode("utf-8"), salt).decode("utf-8")

def check_password(plain: str, hashed: str) -> bool:
    """Сравнивает открытый пароль с bcrypt-хэшем и возвращает результат проверки."""
