def get_user_by_email(email: str, conn: object) -> dict | None:
    """Ищет пользователя по адресу электронной почты и возвращает запись или None."""
    cursor = conn.cursor()
    cursor.execute("SELECT * FROM users WHERE email = ? LIMIT 1", (email.lower().strip(),))
    row = cursor.fetchone()
    if row is None:
        return None
    return dict(zip([d[0] for d in cursor.description], row))

def get_current_user(auth_header: str, secret: str) -> dict | None:
    """Декодирует JWT из заголовка запроса и возвращает данные текущего пользователя."""
    token = parse_auth_header(auth_header)
    if not token:
        return None
    result = verify_jwt_token(token, secret)
    if not result["valid"]:
        return None
    return result["data"]

