def count_users(conn: object, is_active: bool | None = None) -> int:
    """Возвращает общее количество пользователей в таблице с опциональным фильтром."""
    cursor = conn.cursor()
    if is_active is None:
        cursor.execute("SELECT COUNT(*) FROM users")
    else:
        cursor.execute("SELECT COUNT(*) FROM users WHERE is_active = ?", (int(is_active),))
    return cursor.fetchone()[0]

def handle_rate_limit(response: requests.Response) -> None:
    """Обрабатывает ответ 429, ожидая время из заголовка Retry-After перед повтором."""
    if response.status_code != 429:
        return
    retry_after = response.headers.get("Retry-After", "5")
    try:
        wait = float(retry_after)
    except ValueError:
        wait = 5.0
    time.sleep(min(wait, 60.0))

def retry_request(url: str, method: str = "GET", max_retries: int = 3,
                  backoff: float = 1.0, **kwargs) -> requests.Response:
    """Повторяет HTTP-запрос с экспоненциальной задержкой при ошибках соединения."""
    for attempt in range(max_retries):
        try:
            resp = requests.request(method, url, timeout=10, **kwargs)
            resp.raise_for_status()
            return resp
        except requests.RequestException:
            if attempt == max_retries - 1:
                raise
            time.sleep(backoff * (2 ** attempt))

def handle_redirect(url: str, max_hops: int = 5) -> requests.Response:
    """Следует за HTTP-редиректом вручную и возвращает финальный ответ."""
    current_url = url
    for _ in range(max_hops):
        resp = requests.get(current_url, allow_redirects=False, timeout=10)
        if resp.status_code in (301, 302, 303, 307, 308):
            current_url = resp.headers.get("Location", current_url)
        else:
            return resp
    raise RuntimeError(f"Too many redirects for {url}")

