def measure_latency(url: str, method: str = "GET", **kwargs) -> float:
    """Измеряет время ответа HTTP-эндпоинта в миллисекундах."""
    start = time.monotonic()
    try:
        requests.request(method, url, timeout=10, **kwargs)
    except requests.RequestException:
        pass
    return (time.monotonic() - start) * 1000

def proxy_request(target_url: str, method: str, headers: dict,
                  body: bytes | None = None) -> requests.Response:
    """Проксирует входящий запрос на целевой URL и возвращает ответ бэкенда."""
    hop_by_hop = {"connection", "keep-alive", "transfer-encoding", "te",
                  "upgrade", "proxy-authorization", "proxy-authenticate"}
    clean_headers = {k: v for k, v in headers.items() if k.lower() not in hop_by_hop}
    return requests.request(method, target_url, headers=clean_headers,
                            data=body, timeout=15, allow_redirects=False)

def broadcast_to_servers(urls: list[str], payload: dict,
                         headers: dict | None = None) -> list[dict]:
    """Отправляет одинаковый POST-запрос на список серверов и собирает статусы ответов."""
    results = []
    for url in urls:
        try:
            resp = requests.post(url, json=payload, headers=headers or {}, timeout=5)
            results.append({"url": url, "status": resp.status_code, "ok": resp.ok})
        except requests.RequestException as e:
            results.append({"url": url, "status": None, "ok": False, "error": str(e)})
    return results

